import dspy

class BudgetCoT(dspy.Module):
    def __init__(self, budget=200):
        super().__init__()
        self.budget = budget
        self.reason = dspy.ChainOfThought('observation -> reason')
        self.answer = dspy.Predict('reason, question -> answer')

    def forward(self, question):
        observation = 'Solve step by step, max 100 words'
        reason = self.reason(observation=observation, question=question)

        # Enforce budget
        if len(reason.reason) > 100:
            reason.reason = reason.reason[:97] + '...'

        return self.answer(reason=reason.reason, question=question)

budget_cot = BudgetCoT()
result = budget_cot('What is 23*17?')  # Fixed ~120 tokens

import dspy

def cost_metric(example, pred, trace=None):
    base_score = dspy.evaluate.answer_exact_match(example, pred)
    token_penalty = len(pred.completion.split()) / 50  # Normalize to 50 words
    return 1.0 - (1.0 - base_score) + (1.0 - token_penalty)

class CostAwareBootstrap(dspy.BootstrapFewShot):
    def __init__(self):
        super().__init__(metric=cost_metric)

# Compile with cost awareness
